{
  "family": "Houben-Hoesch Reaction/Synthesis",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "COc1cc(OC)cc(OC)c1"
    ],
    "product_smiles": [
      "CC(=O)c1cc(OC)cc(OC)c1"
    ],
    "optional_reagent_smiles": [
      "Cl[Zn]Cl",
      "Cl"
    ],
    "rationale": "This is a classic textbook example of the Houben-Hoesch reaction, featuring the acylation of a highly activated, electron-rich aromatic ring (1,3,5-trimethoxybenzene) with a simple nitrile (acetonitrile). The reaction is catalyzed by a Lewis acid (zinc chloride) and a Brønsted acid (HCl), leading to the formation of an aryl ketone (2,4,6-trimethoxyacetophenone) after hydrolysis of the intermediate ketimine. The reactants and product are simple, acyclic where possible, and clearly illustrate the core transformation of this named reaction.",
    "collision_avoidance_note": "This example avoids using phenol (which could trigger Fries or Reimer-Tiemann queries), benzene (to avoid generic Friedel-Crafts acylation), or complex nitriles. The use of a highly activated methoxy-substituted benzene with a simple nitrile is characteristic of the Houben-Hoesch reaction and distinct from other electrophilic aromatic substitution reactions."
  }
}
